const jwksCache = new JWKSCache(CONFIG.JWKS_URI, CONFIG.JWKS_CACHE_TTL);
const tokenValidator = new TokenValidator(jwksCache, CONFIG);

/**
 * Authentication middleware - validates bearer tokens.
 */
function authenticateToken(requiredScopes = []) {
  return async (req, res, next) => {
    try {
      // Extract bearer token from Authorization header
      const token = tokenValidator.extractBearerToken(req.headers.authorization);

      // Validate the token (signature + claims)
      const { header, payload } = await tokenValidator.validateToken(token);

      // Check required scopes if specified
      if (requiredScopes.length > 0) {
        const tokenScopes = (payload.scope || '').split(' ').filter(Boolean);
        const hasRequiredScopes = requiredScopes.every(scope => tokenScopes.includes(scope));
        if (!hasRequiredScopes) {
          return res.status(403).json({
            error: 'insufficient_scope',
            error_description: `Required scopes: ${requiredScopes.join(' ')}`,
          });
        }
      }

      // Attach validated token info to request for downstream handlers
      req.auth = {
        sub: payload.sub,
        iss: payload.iss,
        aud: payload.aud,
        exp: payload.exp,
        iat: payload.iat,
        jti: payload.jti,
        scope: payload.scope,
        claims: payload,
        header: header,
      };

      next();
    } catch (err) {
      if (err instanceof TokenValidationError) {
        // Log the validation failure (without the token itself for security)
        console.warn(`Token validation failed: ${err.message}`, {
          ip: req.ip,
          path: req.path,
          method: req.method,
          timestamp: new Date().toISOString(),
        });

        // Return RFC 6750 compliant error response
        const statusCode = err.statusCode || 401;
        res.set('WWW-Authenticate', `Bearer realm="api", error="invalid_token", error_description="${err.message}"`);
        return res.status(statusCode).json({
          error: 'invalid_token',
          error_description: err.message,
        });
      }

      // Unexpected errors - don't leak internal details
      console.error('Unexpected authentication error:', err);
      res.set('WWW-Authenticate', 'Bearer realm="api", error="invalid_token"');
      return res.status(401).json({
        error: 'invalid_token',
        error_description: 'Token validation failed',
      });
    }
  };
}

