app.post('/admin/jwks-refresh', authenticateToken(['admin:jwks']), async (req, res) => {
  try {
    await jwksCache.fetchJWKS();
    res.json({ status: 'ok', message: 'JWKS cache refreshed' });
  } catch (err) {
    console.error('JWKS refresh failed:', err);
    res.status(500).json({ error: 'jwks_refresh_failed', error_description: err.message });
  }
});

