// Basic authenticated endpoint
app.get('/api/v1/userinfo', authenticateToken(), (req, res) => {
  res.json({
    sub: req.auth.sub,
    scope: req.auth.scope,
    iss: req.auth.iss,
    exp: req.auth.exp,
  });
});

// Endpoint requiring specific scopes
app.get('/api/v1/resources', authenticateToken(['read:resources']), (req, res) => {
  res.json({
    resources: [],
    requestedBy: req.auth.sub,
    requestId: req.requestId,
  });
});

app.post('/api/v1/resources', authenticateToken(['write:resources']), (req, res) => {
  res.status(201).json({
    message: 'Resource created',
    createdBy: req.auth.sub,
    requestId: req.requestId,
  });
});

// Catch-all for unmatched routes
app.use((req, res) => {
  res.status(404).json({
    error: 'not_found',
    error_description: 'The requested resource was not found',
  });
});

// Global error handler
app.use((err, req, res, _next) => {
  console.error('Unhandled error:', {
    error: err.message,
    stack: err.stack,
    requestId: req.requestId,
    path: req.path,
    method: req.method,
  });

  res.status(500).json({
    error: 'server_error',
    error_description: 'An internal server error occurred',
    requestId: req.requestId,
  });
});

